const comment = $input.first().json.comment.body;
const pr = $input.first().json.issue;
const repo = $input.first().json.repository;

// Count severity levels
const criticalCount = (comment.match(/Critical|\u{1F534}|🔴/gu) || []).length;
const warningCount = (comment.match(/Warning|\u{1F7E1}|🟡/gu) || []).length;
const suggestionCount = (comment.match(/Suggestion|\u{1F7E3}|🟣/gu) || []).length;

// Determine overall status
let status, statusEmoji, color;
if (criticalCount > 0) {
  status = 'Critical Issues Found';
  statusEmoji = '🔴';
  color = 16711680; // Red
} else if (warningCount > 0) {
  status = 'Warnings Found';
  statusEmoji = '🟡';
  color = 16776960; // Yellow
} else {
  status = 'Passed';
  statusEmoji = '✅';
  color = 65280; // Green
}

// Truncate comment for Discord (max 4096 chars)
const truncatedBody = comment.length > 2000 
  ? comment.substring(0, 2000) + '\n\n... (truncated, see full review on GitHub)'
  : comment;

return [{
  json: {
    prNumber: pr.number,
    prTitle: pr.title,
    prUrl: pr.html_url,
    repoName: repo.full_name,
    author: pr.user.login,
    status,
    statusEmoji,
    color,
    criticalCount,
    warningCount,
    suggestionCount,
    reviewBody: truncatedBody,
    timestamp: new Date().toISOString()
  }
}];

parameters.jsonBody:
={
